import Vision
import AVFoundation
import Combine

class HandPoseDetector: ObservableObject {
    @Published var detectedGesture: RPSGesture = .unknown
    @Published var statusMessage: String = "Show your hand and tap Shoot"
    @Published var isAnalyzing: Bool = false

    private var latestBuffer: CMSampleBuffer?
    private let bufferLock = NSLock()

    func captureBuffer(_ buffer: CMSampleBuffer) {
        bufferLock.lock()
        latestBuffer = buffer
        bufferLock.unlock()
    }

    func analyzeCurrentFrame() {
        bufferLock.lock()
        let buffer = latestBuffer
        bufferLock.unlock()

        guard let buffer else {
            DispatchQueue.main.async { self.statusMessage = "No camera frame available" }
            return
        }

        DispatchQueue.main.async { self.isAnalyzing = true }

        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            guard let self else { return }
            let gesture = self.runHandPose(on: buffer)
            DispatchQueue.main.async {
                self.isAnalyzing = false
                self.detectedGesture = gesture
                switch gesture {
                case .rock:     self.statusMessage = "Rock!"
                case .paper:    self.statusMessage = "Paper!"
                case .scissors: self.statusMessage = "Scissors!"
                case .unknown:  self.statusMessage = "No hand detected — try again"
                }
            }
        }
    }

    private func runHandPose(on sampleBuffer: CMSampleBuffer) -> RPSGesture {
        guard let pixelBuffer = CMSampleBufferGetImageBuffer(sampleBuffer) else { return .unknown }
        // Use .right for BOTH front and back camera.
        // Do NOT use .leftMirrored for front camera — it inverts Y and breaks finger extension detection.
        let handler = VNImageRequestHandler(cvPixelBuffer: pixelBuffer, orientation: .right)
        let request = VNDetectHumanHandPoseRequest()
        request.maximumHandCount = 1
        do {
            try handler.perform([request])
        } catch {
            return .unknown
        }
        guard let observation = request.results?.first else { return .unknown }
        return classifyGesture(from: observation)
    }

    // With .right orientation, Y increases upward: extended finger tip has HIGHER Y than its knuckle.
    private func isExtended(tip: VNRecognizedPoint, mcp: VNRecognizedPoint) -> Bool {
        tip.confidence >= 0.7 && mcp.confidence >= 0.7 && tip.location.y > mcp.location.y
    }

    private func classifyGesture(from observation: VNHumanHandPoseObservation) -> RPSGesture {
        guard let indexTip  = try? observation.recognizedPoint(.indexTip),
              let indexMCP  = try? observation.recognizedPoint(.indexMCP),
              let middleTip = try? observation.recognizedPoint(.middleTip),
              let middleMCP = try? observation.recognizedPoint(.middleMCP),
              let ringTip   = try? observation.recognizedPoint(.ringTip),
              let ringMCP   = try? observation.recognizedPoint(.ringMCP),
              let littleTip = try? observation.recognizedPoint(.littleTip),
              let littleMCP = try? observation.recognizedPoint(.littleMCP),
              let thumbTip  = try? observation.recognizedPoint(.thumbTip),
              let thumbCMC  = try? observation.recognizedPoint(.thumbCMC)
        else { return .unknown }

        let indexUp  = isExtended(tip: indexTip,  mcp: indexMCP)
        let middleUp = isExtended(tip: middleTip, mcp: middleMCP)
        let ringUp   = isExtended(tip: ringTip,   mcp: ringMCP)
        let pinkyUp  = isExtended(tip: littleTip, mcp: littleMCP)
        let thumbUp  = isExtended(tip: thumbTip,  mcp: thumbCMC)

        if indexUp && middleUp && ringUp && pinkyUp && thumbUp { return .paper }
        if !indexUp && !middleUp && !ringUp && !pinkyUp        { return .rock }
        if indexUp && middleUp && !ringUp && !pinkyUp          { return .scissors }
        return .unknown
    }
}

enum RPSGesture: String {
    case rock = "Rock", paper = "Paper", scissors = "Scissors", unknown = "Unknown"

    var emoji: String {
        switch self {
        case .rock:     return "✊"
        case .paper:    return "✋"
        case .scissors: return "✌️"
        case .unknown:  return "❓"
        }
    }
}
